#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int x1,y1,x2,y2; scanf("%d %d %d %d",&x1,&y1,&x2,&y2);
        int p1=(x1+y1)&1, p2=(x2+y2)&1;
        puts(p1==p2?"YES":"NO");
    }
    return 0;
}

